-- Table structure for fa_cms_addonproduct
-- ----------------------------
DROP TABLE IF EXISTS `fa_cms_addonproduct`;
CREATE TABLE `fa_cms_addonproduct`  (
  `id` int(10) NOT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `productdata` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '产品列表',
  PRIMARY KEY (`id`) USING BTREE
