-- Table structure for fa_cms_autolink
-- ----------------------------
DROP TABLE IF EXISTS `fa_cms_autolink`;
CREATE TABLE `fa_cms_autolink`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标题',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '链接',
  `target` enum('self','blank') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'blank' COMMENT '打开方式',
  `weigh` int(10) DEFAULT 0 COMMENT '排序',
  `views` int(10) UNSIGNED DEFAULT 0 COMMENT '点击次数',
  `createtime` bigint(16) DEFAULT NULL COMMENT '添加时间',
  `updatetime` bigint(16) DEFAULT NULL COMMENT '更新时间',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'normal' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '自动链接表' ROW_FORMAT = Compact;

