-- ----------------------------
-- Table structure for fa_cms_channel
-- ----------------------------
DROP TABLE IF EXISTS `fa_cms_channel`;
CREATE TABLE `fa_cms_channel`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
