-- ----------------------------
-- Table structure for fa_cms_diyform
-- ----------------------------
DROP TABLE IF EXISTS `fa_cms_diyform`;
CREATE TABLE `fa_cms_diyform`  (
  `id` smallint(5) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `admin_id` int(10) UNSIGNED DEFAULT 0 COMMENT '管理员ID',
  `name` char(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '表单名称',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标题',
  `seotitle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT 'SEO标题',
  `posttitle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '发布标题',
  `keywords` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '关键字',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '描述',
  `table` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '表名',
  `fields` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '字段列表',
  `isguest` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否访客访问',
  `needlogin` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否需要登录发布',
  `isedit` tinyint(1) UNSIGNED DEFAULT 0 COMMENT '是否允许编辑',
  `iscaptcha` tinyint(1) UNSIGNED DEFAULT 0 COMMENT '是否启用验证码',
  `successtips` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '成功提示文字',
  `redirecturl` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '成功后跳转链接',
  `posttpl` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '表单页模板',
  `listtpl` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '列表页模板',
  `showtpl` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '详情页模板',
  `diyname` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '自定义名称',
  `usermode` enum('all','user') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'all' COMMENT '用户筛选模式',
  `statusmode` enum('all','normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'all' COMMENT '状态筛选模式',
  `createtime` bigint(16) DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint(16) DEFAULT NULL COMMENT '更新时间',
  `setting` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '表单配置',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'hidden' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `diyname`(`diyname`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '自定义表单表' ROW_FORMAT = Compact;

