-- Table structure for fa_cms_diyform_tianjiabaoguo
-- ----------------------------
DROP TABLE IF EXISTS `fa_cms_diyform_tianjiabaoguo`;
CREATE TABLE `fa_cms_diyform_tianjiabaoguo`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(10) DEFAULT NULL COMMENT '会员ID',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '标题',
  `images` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '图片',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '内容',
  `createtime` bigint(16) DEFAULT NULL COMMENT '添加时间',
