  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `orderid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '订单ID',
  `user_id` int(10) UNSIGNED DEFAULT 0 COMMENT '会员ID',
  `archives_id` int(10) UNSIGNED DEFAULT 0 COMMENT '文档ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单标题',
  `amount` decimal(10, 2) UNSIGNED DEFAULT 0.00 COMMENT '订单金额',
  `payamount` decimal(10, 2) UNSIGNED DEFAULT 0.00 COMMENT '支付金额',
  `paytype` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付类型',
  `paytime` bigint(16) DEFAULT NULL COMMENT '支付时间',
  `method` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '支付方法',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'IP地址',
  `useragent` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'UserAgent',
  `memo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `createtime` bigint(16) DEFAULT NULL COMMENT '添加时间',
  `updatetime` bigint(16) DEFAULT NULL COMMENT '更新时间',
  `status` enum('created','paid','expired') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'created' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `archives_id`(`archives_id`) USING BTREE,
  INDEX `orderid`(`orderid`) USING BTREE,
  INDEX `orderid_2`(`orderid`) USING BTREE
